async (page) => {
  await page.goto('http://localhost:9000');
  await page.waitForTimeout(2000);

  // Patch WebSocket BEFORE login
  await page.evaluate((p) => {
    const OrigWS = window.WebSocket;
    window.WebSocket = function(url, ...args) {
      url = url.replace(/:9001\b/, ':' + p);
      console.log('WS connecting to:', url);
      return new OrigWS(url, ...args);
    };
    window.WebSocket.prototype = OrigWS.prototype;
  }, '9031');
  await page.waitForTimeout(500);

  await page.locator('#login-name-input').fill('ClaudeBot3');
  await page.locator('#login-password-input').fill('password123');
  await page.getByRole('button', { name: 'Login' }).click();
  await page.waitForTimeout(10000);

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return 'Login attempt done';
}
